const msg = $input.item.json.message || {};
const canal = 'telegram';
const chat_id = String(msg.chat?.id || '');
const message_id = String(msg.message_id || '');
const texto = msg.text || '';
const first_name = msg.from?.first_name || '';
const last_name = msg.from?.last_name || '';
const nome_usuario = (first_name + ' ' + last_name).trim() || 'Cliente Telegram';
const username = msg.from?.username || '';

let hash_mensagem = message_id;
if (!message_id) {
  const min = new Date().toISOString().substring(0, 16); // yyyy-mm-ddThh:mm
  hash_mensagem = canal + '_' + chat_id + '_' + texto.substring(0, 50) + '_' + min;
}

return [{
  json: {
    canal,
    chat_id,
    message_id,
    hash_mensagem,
    nome_usuario,
    username,
    texto
  }
}];

const normalizado = $node["Normalizar Entrada"].json;
const conversa = $items("Buscar Conversa");

let contexto = {
  intencao_atual: "indefinido",
  etapa_funil: "inicio",
  segmento: "indefinido",
  dados_coletados: {},
  ultima_mensagem: "",
  ultima_resposta: ""
};

const firstItem = (conversa.length > 0) ? conversa[0].json : null;
const c = (firstItem && !firstItem.error) ? (Array.isArray(firstItem) ? firstItem[0] : firstItem) : null;
if (c && c.id) {
  contexto.intencao_atual = c.intencao_atual || "indefinido";
  contexto.etapa_funil = c.etapa_funil || "inicio";
  contexto.segmento = c.segmento || "indefinido";
  contexto.dados_coletados = c.dados_coletados || {};
  contexto.ultima_mensagem = c.ultima_mensagem || "";
  contexto.ultima_resposta = c.ultima_resposta || "";
}

return [{
  json: {
    canal: normalizado.canal,
    chat_id: normalizado.chat_id,
    message_id: normalizado.message_id,
    nome_usuario: normalizado.nome_usuario,
    username: normalizado.username,
    mensagem_atual: normalizado.texto,
    contexto: contexto
  }
}];

const err = $node["Aninha Atendimento"].json.error || $node["Aninha Atendimento"].json;
let userMsg = '';
try {
  userMsg = ($node["Normalizar Entrada"].json.texto || '').toLowerCase();
} catch (e) {
  userMsg = '';
}

const residentialKeywords = [
  "apartamento", "apto", "minha casa", "residência", "residencial", 
  "chuveiro", "tomada", "disjuntor do meu apartamento", "casa"
];
let isResidential = false;
for (const keyword of residentialKeywords) {
  if (userMsg.includes(keyword)) {
    isResidential = true;
    break;
  }
}

let result = {};
if (isResidential) {
  result = {
    responder_cliente: true,
    resposta_cliente: "No momento, a DL Soluções Condominiais atende demandas técnicas voltadas a condomínios, escolas, empresas e suporte a equipamentos profissionais. Para esse tipo de solicitação residencial avulsa, não conseguimos seguir com atendimento.",
    intencao_atual: "residencial_bloqueado",
    etapa_funil: "bloqueado_residencial",
    segmento: "residencial",
    dados_coletados: {},
    lead_qualificado: false,
    encaminhar_humano: false,
    motivo_encaminhamento: null,
    bloquear: true,
    motivo_bloqueio: "atendimento residencial avulsa",
    is_fallback: true,
    error_details: JSON.stringify(err)
  };
} else {
  result = {
    responder_cliente: true,
    resposta_cliente: "Recebi sua mensagem. Para seguir com a Avaliação Técnica, me informe o nome do condomínio, bairro e o problema principal identificado.",
    intencao_atual: "indefinido",
    etapa_funil: "coletando_dados_condominio",
    segmento: "indefinido",
    dados_coletados: {},
    lead_qualificado: false,
    encaminhar_humano: false,
    motivo_encaminhamento: null,
    bloquear: false,
    motivo_bloqueio: null,
    is_fallback: true,
    error_details: JSON.stringify(err)
  };
}

return [{ json: result }];

const normalizado = $node["Normalizar Entrada"].json;
const motor = $node["Obter Resposta Final"].json;

const events = [];

events.push({
  canal: "telegram",
  chat_id: normalizado.chat_id,
  message_id: normalizado.message_id,
  direcao: "entrada",
  tipo_evento: "entrada_usuario",
  conteudo: normalizado.texto,
  payload: {}
});

events.push({
  canal: "telegram",
  chat_id: normalizado.chat_id,
  message_id: "",
  direcao: "saida",
  tipo_evento: "resposta_aninha",
  conteudo: motor.resposta_cliente,
  payload: motor
});

if (motor.lead_qualificado) {
  events.push({
    canal: "telegram",
    chat_id: normalizado.chat_id,
    message_id: "",
    direcao: "sistema",
    tipo_evento: "lead_qualificado",
    conteudo: "Lead qualificado pela Aninha",
    payload: motor.dados_coletados
  });
}

if (motor.etapa_funil === "bloqueado_residencial") {
  events.push({
    canal: "telegram",
    chat_id: normalizado.chat_id,
    message_id: "",
    direcao: "sistema",
    tipo_evento: "bloqueio_residencial",
    conteudo: "Residencial bloqueado",
    payload: { motivo: motor.motivo_bloqueio }
  });
}

return events.map(e => ({ json: e }));

